//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {
  // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if (!(await $c.gus.cfCanOpenPopup($p, inObj, pairObj))) return;

  // 짝이 되는 오브젝트의 값 제거
  $c.gus.cfClearPairObj($p, pairObj);

  // 검색어 세팅
  var pVal = $c.gus.cfGetValue($p, inObj);

  // inObj가 코드 필드일 경우 팝업
  if (isCode == null || isCode == true) scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
  // inObj가 코드명 필드일 경우 팝업
  else scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

//-------------------------------------------------------------------------
// 전표일자, 공급일자 일자일괄적용
//------------------------------------------------------------------------- 
scwin.f_adaptSlipDt = async function () {
  var chkCnt = 0;
  var stPos = ds_dnTrustTaxInvoice.getRowPosition();
  var slipDt = ds_dnTrustTaxInvoice.getCellData(stPos, "slipDt");
  var spplyDt = ds_dnTrustTaxInvoice.getCellData(stPos, "spplyDt");
  var reqDt = ds_dnTrustTaxInvoice.getCellData(stPos, "reqDt");
  for (var i = 0; i < ds_dnTrustTaxInvoice.getRowCount(); i++) {
    if (ds_dnTrustTaxInvoice.getCellData(i, "choice") == "T") {
      ds_dnTrustTaxInvoice.setCellData(i, "slipDt", slipDt);
      ds_dnTrustTaxInvoice.setCellData(i, "spplyDt", spplyDt);
      ds_dnTrustTaxInvoice.setCellData(i, "reqDt", reqDt);
      chkCnt++;
    }
  }
  if (chkCnt == 0) {
    await $c.win.alert($p, "선택된 행이 없습니다. 일괄적용할 행들을 선택해 주십시오.");
    return false;
  }
};

//-------------------------------------------------------------------------
// 전도금 미지급금 계정일괄적용 20170807
//------------------------------------------------------------------------- 
scwin.f_adaptAcctGubun = async function () {
  var chkCnt = 0;
  var gubun = rd_acctGubun.getValue(); // gubun 0:전도금 1:미지급금
  var acctClntNo = ed_acctClntNo.getValue(); // 미지급거래처

  if (gubun == "1" && acctClntNo == "") {
    await $c.win.alert($p, "미지급금인 경우 미지급거래처를 입력하세요.");
    return;
  }
  //scwin.dataSetDebug(ds_dnTrustTaxInvoice,true);
  for (var i = 0; i < ds_dnTrustTaxInvoice.getRowCount(); i++) {
    if (ds_dnTrustTaxInvoice.getCellData(i, "choice") == "T") {
      ds_dnTrustTaxInvoice.setCellData(i, "acctGubun", gubun);
      if (gubun == "1") {
        ds_dnTrustTaxInvoice.setCellData(i, "bilgClntNo", acctClntNo);
      } else {
        ds_dnTrustTaxInvoice.setCellData(i, "bilgClntNo", "280161"); //20170822 성원영대리님 요청(전도금-일반계정의 귀속부서만 00915)
      }
      chkCnt++;
    }
  }
  if (chkCnt == 0) {
    await $c.win.alert($p, "선택된 행이 없습니다. 일괄적용할 행들을 선택해 주십시오.");
    return;
  }
};

//-------------------------------------------------------------------------
// 검색영역 Field Clear함.
