scwin.f_reqPayMthdCd = async function () {
  var gubun = acb_payMthdCd.getValue();
  var chkCnt = 0;
  for (var i = 0; i < ds_dnTrustTaxInvoice.getRowCount(); i++) {
    if (ds_dnTrustTaxInvoice.getCellData(i, "choice") == "T") {
      ds_dnTrustTaxInvoice.setCellData(i, "reqPayMthdCd", gubun);
      chkCnt++;
    }
  }
  if (chkCnt == 0) {
    await $c.win.alert($p, "선택된 행이 없습니다. 일괄적용할 행들을 선택해 주십시오.");
    return;
  }
};
